const envelope = $('Configurar IDs e Regras').item.json;
const body = envelope.payload?.body || {};
const config = envelope.config;
const data = $getWorkflowStaticData('global');

const baseUrl = config.chatwootBaseUrl;
const apiToken = config.token;
const event = body.event;
const DEFAULT_ACCOUNT_ID = config.accountId || 2;

const accountId =
  body.account?.id ||
  body.account_id ||
  body.conversation?.account_id ||
  body.messages?.[0]?.account_id ||
  DEFAULT_ACCOUNT_ID;

const conversationId =
  body.conversation?.id ||
  body.id ||
  body.messages?.[0]?.conversation_id;

const inboxId =
  body.inbox?.id ||
  body.inbox_id ||
  body.conversation?.inbox_id;

const messageId = body.id || body.messages?.[0]?.id || null;
const sourceId = body.source_id || body.messages?.[0]?.source_id || '';

const contentRaw = body.content || body.messages?.[0]?.content || '';
const content = String(contentRaw || '').trim();
const normalized = content.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

const rawMessageType = body.message_type;
const numericMessageType = body.messages?.[0]?.message_type;
const messageType =
  rawMessageType ||
  (numericMessageType === 0 ? 'incoming' : numericMessageType === 1 ? 'outgoing' : numericMessageType);

const isPrivate = body.private === true || body.messages?.[0]?.private === true;
const conversation = body.conversation || body;
const attrs = conversation.custom_attributes || {};
const labels = conversation.labels || body.labels || [];
const status = body.status || conversation.status || '';

const isClientMessage = event === 'message_created' && messageType === 'incoming' && !isPrivate;
const isAgentMessage = event === 'message_created' && messageType === 'outgoing' && !isPrivate;
const isResolvedConversation = event === 'conversation_status_changed' && status === 'resolved';

const looksLikeBotOutgoing =
  content.includes('Olá! Seja bem-vindo') ||
  content.includes('Perfeito! Vou te direcionar') ||
  content.includes('Ótimo! Já estou conectando') ||
  content.includes('Dados recebidos com sucesso') ||
  content.includes('Como ainda não houve resposta') ||
  content.includes('Só passando pra ver se ainda posso te ajudar') ||
  content.includes('Como não tivemos retorno');
const isCreatedConversation = event === 'conversation_created';
const isOpenConversation = event === 'conversation_status_changed' && status === 'open';

const etapa = attrs.etapa || '';
const fluxo = attrs.fluxo || '';
const fallback = Number(attrs.fallback_count || 0);
const nowIso = new Date().toISOString();
const resolvedKey = `resolved_${conversationId}`;
const lastMenuKey = `last_menu_sent_${conversationId}`;

function canSendMenuNow() {
  const last = Number(data[lastMenuKey] || 0);
  return Date.now() - last > 20000;
}

function markMenuSent() {
  data[lastMenuKey] = Date.now();
}

const menuPrincipal =
`Olá! Seja bem-vindo(a) à Zambianqui Ambiental 👋

É um prazer te atender! Para levar sua mensagem à pessoa certa, me conta:

1️⃣ – Meio Ambiente / Georreferenciamento
2️⃣ – Segurança do Trabalho

É só digitar o número da opção! 😊`;

const submenuMA =
`Perfeito! Vou te direcionar para a equipe de Meio Ambiente 🌿

Como podemos te ajudar hoje?

1️⃣ – Orçamentos e Informações Comerciais
2️⃣ – Suporte Técnico / Andamento de Processo
3️⃣ – Financeiro MA / Pagamentos

Digite o número da opção!`;

const submenuSST =
`Perfeito! Vou te direcionar para a equipe de Segurança do Trabalho 🦺

Como podemos te ajudar hoje?

1️⃣ – Orçamentos e Informações Comerciais
2️⃣ – ASO / Atestado de Saúde Ocupacional
3️⃣ – Técnico / Laudos e Documentos
4️⃣ – Financeiro SST / Pagamentos

Digite o número da opção!`;

const transferMsg =
`Ótimo! Já estou conectando você com nossa equipe 🟢

Em instantes alguém te atende.
Obrigado pela paciência! 😊`;

const foraHorarioMsg =
`Olá! Obrigado por entrar em contato com a Zambianqui Ambiental 💚

No momento estamos fora do horário de atendimento.

🕗 Segunda a sexta: 8h às 12h | 13h30 às 18h

Sua mensagem foi registrada e retornamos assim que abrirmos! Até logo 😊`;

async function api(method, path, body) {
  const res = await this.helpers.httpRequest({
    method,
    url: `${baseUrl}${path}`,
    headers: { api_access_token: apiToken, 'Content-Type': 'application/json' },
    body,
    json: true,
  });
  return res || {};
}

// Obtém horário diretamente do Chatwoot.
// Se a sua versão do Chatwoot não retornar working_hours/open_hours no endpoint da inbox,
// o fluxo assume "aberto" para não bloquear atendimento.
async function isInboxOpenFromChatwoot() {
  if (!inboxId) return true;

  let inbox = {};
  try {
    inbox = await api.call(this, 'GET', `/api/v1/accounts/${accountId}/inboxes/${inboxId}`);
  } catch (e) {
    return true;
  }

  const enabled =
    inbox.working_hours_enabled ??
    inbox.enable_working_hours ??
    inbox.out_of_office_enabled ??
    false;

  if (!enabled) return true;

  const hours =
    inbox.working_hours ||
    inbox.open_hours ||
    inbox.working_hours_config ||
    inbox.availability?.working_hours ||
    [];

  if (!Array.isArray(hours) || hours.length === 0) return true;

  const tz = inbox.timezone || inbox.time_zone || 'America/Sao_Paulo';
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: tz,
    weekday: 'short',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).formatToParts(new Date());

  const wdText = parts.find(p => p.type === 'weekday')?.value;
  const hour = Number(parts.find(p => p.type === 'hour')?.value);
  const minute = Number(parts.find(p => p.type === 'minute')?.value);
  const wdMap = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
  const day = wdMap[wdText];

  function dayMatches(rule) {
    const d = rule.day_of_week ?? rule.day ?? rule.weekday;
    if (typeof d === 'number') return d === day || d === day + 1;
    if (typeof d === 'string') return d.toLowerCase().startsWith(wdText.toLowerCase().slice(0, 3));
    return false;
  }

  function toMinutes(h, m) {
    return Number(h || 0) * 60 + Number(m || 0);
  }

  const nowMin = hour * 60 + minute;

  for (const rule of hours) {
    if (!dayMatches(rule)) continue;
    if (rule.closed_all_day === true || rule.closed === true) return false;
    if (rule.open_all_day === true) return true;

    const open = rule.open_time || rule.from || rule.start_time;
    const close = rule.close_time || rule.to || rule.end_time;

    let start, end;

    if (typeof open === 'string' && typeof close === 'string') {
      const [oh, om] = open.split(':').map(Number);
      const [ch, cm] = close.split(':').map(Number);
      start = toMinutes(oh, om);
      end = toMinutes(ch, cm);
    } else {
      start = toMinutes(rule.open_hour ?? rule.start_hour, rule.open_minutes ?? rule.start_minute);
      end = toMinutes(rule.close_hour ?? rule.end_hour, rule.close_minutes ?? rule.end_minute);
    }

    if (nowMin >= start && nowMin <= end) return true;
  }

  return false;
}

function token() {
  return `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
}

function merged(nextAttrs) {
  return { ...attrs, ...nextAttrs };
}

function result(overrides = {}) {
  return {
    accountId,
    conversationId,
    inboxId,
    event,
    status,
    content,
    normalized,
    attrs,
    labels,

    shouldResetOnStart: false,
    shouldSend: false,
    shouldSaveAttributes: false,
    shouldSetLabels: false,
    shouldClearAssignment: false,
    shouldAssignTeam: false,

    message: '',
    privateMessage: false,
    customAttributes: {},
    labelsToSet: [],
    targetTeamId: 0,
    targetTeamName: '',
    debug_reason: '',
    ...overrides
  };
}

function waitAttrs(nextAttrs) {
  return merged({
    ...nextAttrs,
    aguardando_cliente: 'true',
    inactivity_token: token(),
    inactivity_started_at: nowIso,
    ultima_interacao_bot: nowIso
  });
}

function noBotWaitAttrs(nextAttrs) {
  return merged({
    ...nextAttrs,
    aguardando_cliente: 'false',
    inactivity_token: '',
    inactivity_started_at: '',
    ultima_interacao_bot: nowIso
  });
}

function outsideHours(reason) {
  return result({
    shouldResetOnStart: true,
    shouldSetLabels: true,
    labelsToSet: ['bot', 'novo_atendimento'],
    shouldClearAssignment: true,
    shouldSend: true,
    message: foraHorarioMsg,
    shouldSaveAttributes: true,
    customAttributes: {
      fluxo: 'fora_horario',
      submenu: '',
      etapa: 'fora_horario',
      empresa: '',
      colaborador: '',
      cpf: '',
      funcao: '',
      tipo_exame: '',
      fallback_count: '0',
      aguardando_cliente: 'false',
      inactivity_token: '',
      inactivity_started_at: '',
      aguardando_agente: 'false',
      aguardando_cliente_humano: 'false',
      lembrete_cliente_enviado: 'false',
      ultima_interacao_bot: nowIso
    },
    debug_reason: reason
  });
}

async function startMenu(reason) {
  const open = await isInboxOpenFromChatwoot.call(this);
  if (!open) return outsideHours('fora_horario_' + reason);

  if (!canSendMenuNow()) {
    return result({ debug_reason: 'menu_suprimido_anti_duplicidade_' + reason });
  }

  delete data[resolvedKey];
  markMenuSent();

  return result({
    shouldResetOnStart: true,
    shouldSetLabels: true,
    labelsToSet: ['bot', 'novo_atendimento'],
    shouldClearAssignment: true,
    shouldSend: true,
    message: menuPrincipal,
    shouldSaveAttributes: true,
    customAttributes: {
      fluxo: 'menu_principal',
      submenu: '',
      etapa: 'aguardando_menu_principal',
      empresa: '',
      colaborador: '',
      cpf: '',
      funcao: '',
      tipo_exame: '',
      fallback_count: '0',
      aguardando_cliente: 'true',
      inactivity_token: token(),
      inactivity_started_at: nowIso,
      aguardando_agente: 'false',
      aguardando_cliente_humano: 'false',
      lembrete_cliente_enviado: 'false',
      ultima_interacao_bot: nowIso
    },
    debug_reason: reason
  });
}

function startMenuFromConversationEvent(reason) {
  if (!canSendMenuNow()) {
    return result({ debug_reason: 'menu_suprimido_anti_duplicidade_' + reason });
  }

  delete data[resolvedKey];
  markMenuSent();

  return result({
    shouldResetOnStart: true,
    shouldSetLabels: true,
    labelsToSet: ['bot', 'novo_atendimento'],
    shouldClearAssignment: true,
    shouldSend: true,
    message: menuPrincipal,
    shouldSaveAttributes: true,
    customAttributes: {
      fluxo: 'menu_principal',
      submenu: '',
      etapa: 'aguardando_menu_principal',
      empresa: '',
      colaborador: '',
      cpf: '',
      funcao: '',
      tipo_exame: '',
      fallback_count: '0',
      aguardando_cliente: 'true',
      inactivity_token: token(),
      inactivity_started_at: nowIso,
      aguardando_agente: 'false',
      aguardando_cliente_humano: 'false',
      lembrete_cliente_enviado: 'false',
      ultima_interacao_bot: nowIso
    },
    debug_reason: reason
  });
}

function fallbackMenu(currentEtapa, currentFluxo, currentSubmenu, menuText) {
  if (fallback >= 1) {
    const teamId = 0;
    return result({
      shouldSend: true,
      message: 'Sem problema! Vou te conectar com nossa equipe agora.\nUm momento! 🟢',
      shouldSaveAttributes: true,
      customAttributes: noBotWaitAttrs({
        fluxo: currentFluxo || fluxo || 'atendimento',
        submenu: currentSubmenu || attrs.submenu || '',
        etapa: 'aguardando_humano',
        fallback_count: '0',
        aguardando_agente: 'true',
        aguardando_cliente_humano: 'false',
        humano_started_at: nowIso,
        last_customer_message_at: nowIso,
        last_agent_message_at: '',
        transbordo_realizado: 'false',
        lembrete_cliente_enviado: 'false'
      }),
      shouldAssignTeam: teamId > 0,
      targetTeamId: teamId,
      targetTeamName: 'Sem fila geral',
      debug_reason: 'fallback_2_transferir_humano'
    });
  }

  return result({
    shouldSend: true,
    message: `Oi! Não consegui entender sua mensagem 😊

Pode digitar o número da opção desejada?

${menuText}`,
    shouldSaveAttributes: true,
    customAttributes: waitAttrs({
      fluxo: currentFluxo || fluxo || 'menu_principal',
      submenu: currentSubmenu || attrs.submenu || '',
      etapa: currentEtapa,
      fallback_count: String(fallback + 1)
    }),
    debug_reason: 'fallback_1_repetir_menu'
  });
}

function ask(message, nextAttrs, reason) {
  return result({
    shouldSend: true,
    message,
    shouldSaveAttributes: true,
    customAttributes: waitAttrs(nextAttrs),
    debug_reason: reason
  });
}

function transferToHuman({flow, submenu, teamKey, teamName, labelsToSet = []}) {
  const teamId = Number(config.teams[teamKey] || 0);
  return result({
    shouldSend: true,
    message: transferMsg,
    shouldSaveAttributes: true,
    customAttributes: noBotWaitAttrs({
      fluxo: flow,
      submenu,
      etapa: 'aguardando_humano',
      fallback_count: '0',
      aguardando_agente: 'true',
      aguardando_cliente_humano: 'false',
      humano_started_at: nowIso,
      last_customer_message_at: nowIso,
      last_agent_message_at: '',
      transbordo_realizado: 'false',
      lembrete_cliente_enviado: 'false'
    }),
    shouldSetLabels: labelsToSet.length > 0,
    labelsToSet,
    shouldAssignTeam: teamId > 0,
    targetTeamId: teamId,
    targetTeamName: teamName,
    debug_reason: `transferir_${teamName}`
  });
}

if (!conversationId || !accountId) return [{ json: result({ debug_reason: 'sem_account_ou_conversation' }) }];

// Nova conversa OU conversa reaberta:
// limpa labels, time e agente, mas NÃO envia menu aqui.
// O menu será enviado apenas no message_created/incoming,
// evitando duplicidade quando o Chatwoot dispara múltiplos eventos.
if (isCreatedConversation || isOpenConversation) {
  delete data[resolvedKey];

  return [{
    json: result({
      shouldResetOnStart: true,
      shouldSetLabels: true,
      labelsToSet: ['bot', 'novo_atendimento'],
      shouldClearAssignment: true,
      shouldSaveAttributes: false,
      debug_reason: isCreatedConversation ? 'nova_conversa_reset_operacional' : 'conversa_reaberta_reset_operacional'
    })
  }];
}

if (isResolvedConversation) {
  data[resolvedKey] = Date.now();
  return [{
    json: result({
      shouldSaveAttributes: true,
      customAttributes: {
        fluxo: 'encerrado',
        submenu: '',
        etapa: 'encerrado',
        empresa: '',
        colaborador: '',
        cpf: '',
        funcao: '',
        tipo_exame: '',
        fallback_count: '0',
        aguardando_cliente: 'false',
        inactivity_token: '',
        inactivity_started_at: '',
        aguardando_agente: 'false',
        aguardando_cliente_humano: 'false',
        lembrete_cliente_enviado: 'false',
        ultima_interacao_bot: nowIso
      },
      debug_reason: 'conversa_resolvida_estado_encerrado'
    })
  }];
}

if (isAgentMessage && !looksLikeBotOutgoing && (String(etapa).startsWith('aguardando_humano') || etapa === 'atendimento_humano')) {
  return [{
    json: result({
      shouldSaveAttributes: true,
      customAttributes: merged({
        etapa: 'atendimento_humano',
        aguardando_agente: 'false',
        aguardando_cliente_humano: 'true',
        last_agent_message_at: nowIso,
        lembrete_cliente_enviado: 'false',
        lembrete_cliente_enviado_at: '',
        ultima_interacao_bot: nowIso
      }),
      debug_reason: 'atendente_respondeu_aguardando_cliente'
    })
  }];
}

if (isClientMessage && (String(etapa).startsWith('aguardando_humano') || etapa === 'atendimento_humano')) {
  return [{
    json: result({
      shouldSaveAttributes: true,
      customAttributes: merged({
        etapa: 'aguardando_humano',
        aguardando_agente: 'true',
        aguardando_cliente_humano: 'false',
        last_customer_message_at: nowIso,
        lembrete_cliente_enviado: 'false',
        lembrete_cliente_enviado_at: '',
        ultima_interacao_bot: nowIso
      }),
      debug_reason: 'cliente_respondeu_aguardando_agente'
    })
  }];
}

if (!isClientMessage) return [{ json: result({ debug_reason: `ignorado_evento_${event}_${status}` }) }];

if (data[resolvedKey] || !etapa || etapa === 'encerrado' || etapa === 'finalizado' || etapa === 'fora_horario') {
  return [{ json: await startMenu.call(this, 'iniciar_fluxo_por_mensagem_cliente') }];
}

if (etapa === 'aguardando_menu_principal') {
  if (normalized === '1') {
    return [{ json: ask(submenuMA, { fluxo: 'meio_ambiente', submenu: 'menu_ma', etapa: 'aguardando_submenu_ma', fallback_count: '0' }, 'submenu_ma') }];
  }
  if (normalized === '2') {
    return [{ json: ask(submenuSST, { fluxo: 'sst', submenu: 'menu_sst', etapa: 'aguardando_submenu_sst', fallback_count: '0' }, 'submenu_sst') }];
  }
  return [{ json: fallbackMenu('aguardando_menu_principal', 'menu_principal', '', '1️⃣ – Meio Ambiente / Georreferenciamento\n2️⃣ – Segurança do Trabalho') }];
}

if (etapa === 'aguardando_submenu_ma') {
  if (normalized === '1') return [{ json: transferToHuman({ flow: 'meio_ambiente', submenu: 'comercial_ma', teamKey: 'comercial_ma', teamName: 'Comercial MA', labelsToSet: ['bot', 'novo_atendimento', 'ma-lead'] }) }];
  if (normalized === '2') return [{ json: transferToHuman({ flow: 'meio_ambiente', submenu: 'tecnico_ma', teamKey: 'tecnico_ma', teamName: 'Técnico MA', labelsToSet: ['bot', 'novo_atendimento'] }) }];
  if (normalized === '3') return [{ json: transferToHuman({ flow: 'meio_ambiente', submenu: 'financeiro_ma', teamKey: 'financeiro_ma', teamName: 'Financeiro MA', labelsToSet: ['bot', 'novo_atendimento'] }) }];
  return [{ json: fallbackMenu('aguardando_submenu_ma', 'meio_ambiente', 'menu_ma', '1️⃣ – Orçamentos e Informações Comerciais\n2️⃣ – Suporte Técnico / Andamento de Processo\n3️⃣ – Financeiro MA / Pagamentos') }];
}

if (etapa === 'aguardando_submenu_sst') {
  if (normalized === '1') return [{ json: transferToHuman({ flow: 'sst', submenu: 'comercial_sst', teamKey: 'comercial_sst', teamName: 'Comercial SST', labelsToSet: ['bot', 'novo_atendimento', 'sst-lead'] }) }];
  if (normalized === '3') return [{ json: transferToHuman({ flow: 'sst', submenu: 'tecnico_sst', teamKey: 'tecnico_sst', teamName: 'Técnico SST', labelsToSet: ['bot', 'novo_atendimento'] }) }];
  if (normalized === '4') return [{ json: transferToHuman({ flow: 'sst', submenu: 'financeiro_sst', teamKey: 'financeiro_sst', teamName: 'Financeiro SST', labelsToSet: ['bot', 'novo_atendimento'] }) }];
  if (normalized === '2') {
    return [{ json: ask(`Olá! Para gerarmos o ASO com agilidade, preciso de algumas informações 📋

Primeiro, me informe o nome da empresa.`, { fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_empresa', fallback_count: '0' }, 'iniciar_aso') }];
  }
  return [{ json: fallbackMenu('aguardando_submenu_sst', 'sst', 'menu_sst', '1️⃣ – Orçamentos e Informações Comerciais\n2️⃣ – ASO / Atestado de Saúde Ocupacional\n3️⃣ – Técnico / Laudos e Documentos\n4️⃣ – Financeiro SST / Pagamentos') }];
}

if (etapa === 'aso_aguardando_empresa') {
  return [{ json: ask('Perfeito. Agora me informe o nome completo do colaborador.', { empresa: content, fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_colaborador', fallback_count: '0' }, 'aso_empresa_salva') }];
}

if (etapa === 'aso_aguardando_colaborador') {
  return [{ json: ask('Obrigado. Agora me informe o CPF do colaborador.', { colaborador: content, fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_cpf', fallback_count: '0' }, 'aso_colaborador_salvo') }];
}

if (etapa === 'aso_aguardando_cpf') {
  const cpfDigits = normalized.replace(/\D/g, '');
  if (cpfDigits.length !== 11) {
    return [{ json: ask('O CPF parece estar em formato inválido. Por favor, envie com 11 números. Exemplo: 12345678900', { fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_cpf' }, 'cpf_invalido') }];
  }
  return [{ json: ask('Certo. Agora me informe a função exercida pelo colaborador.', { cpf: cpfDigits, fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_funcao', fallback_count: '0' }, 'aso_cpf_salvo') }];
}

if (etapa === 'aso_aguardando_funcao') {
  return [{ json: ask(`Perfeito. Agora informe o tipo de exame:

1️⃣ – Admissional
2️⃣ – Periódico
3️⃣ – Demissional
4️⃣ – Retorno ao trabalho
5️⃣ – Mudança de função`, { funcao: content, fluxo: 'sst', submenu: 'aso_sst', etapa: 'aso_aguardando_tipo_exame', fallback_count: '0' }, 'aso_funcao_salva') }];
}

