const response = $json || {};
const config = $('Configurar IDs e Regras').item.json.config;
const now = Date.now();

function minutesSince(iso) {
  if (!iso) return 0;
  const t = new Date(iso).getTime();
  if (Number.isNaN(t)) return 0;
  return (now - t) / 60000;
}

function extractConversations(response) {
  if (Array.isArray(response)) return response;
  if (Array.isArray(response.payload)) return response.payload;
  if (Array.isArray(response.data?.payload)) return response.data.payload;
  if (Array.isArray(response.conversations)) return response.conversations;
  return [];
}

function attrsOf(c) {
  return c.custom_attributes || c.additional_attributes?.custom_attributes || {};
}

function labelsOf(c) {
  return c.labels || [];
}

const msgBotInativo =
`Olá! 😊

Como não tivemos retorno, vou encerrar esta etapa do atendimento automático por aqui.

Quando quiser continuar, é só mandar uma nova mensagem que iniciamos novamente. 💚`;

const msgTransbordo =
`Como ainda não houve resposta da fila, estou direcionando seu atendimento para nosso time de apoio. 🟢`;

const msgLembrete =
`Oi! Tudo bem? 😊

Só passando pra ver se ainda posso te ajudar com alguma coisa!

Se precisar, é só responder aqui 🟢`;

const msgEncerramento =
`Olá! 😊

Como não tivemos retorno, vamos encerrar esse atendimento por aqui.

Qualquer coisa é só mandar mensagem — estaremos prontos para te ajudar!

Até logo! 💚
_Zambianqui Ambiental_`;

const conversations = extractConversations(response);
const actions = [];

for (const c of conversations) {
  const id = c.id;
  const attrs = attrsOf(c);
  const labels = labelsOf(c);
  const etapa = attrs.etapa || '';
  const fluxo = attrs.fluxo || '';

  // 1) Cliente parou de responder no bot
  if (
    attrs.aguardando_cliente === 'true' &&
    !String(etapa).startsWith('aguardando_humano') &&
    etapa !== 'atendimento_humano' &&
    minutesSince(attrs.inactivity_started_at) >= Number(config.regrasMinutos.botInatividadeMinutos)
  ) {
    actions.push({
      json: {
        conversationId: id,
        action: 'bot_inatividade',
        shouldSend: true,
        message: msgBotInativo,
        shouldResolve: true,
        shouldSaveAttributes: true,
        customAttributes: {
          ...attrs,
          fluxo: 'encerrado',
          submenu: '',
          etapa: 'encerrado',
          aguardando_cliente: 'false',
          inactivity_token: '',
          inactivity_started_at: '',
          ultima_interacao_bot: new Date().toISOString()
        }
      }
    });
    continue;
  }

  // 2) Fila sem atendente responder
  if (
    attrs.aguardando_agente === 'true' &&
    attrs.transbordo_realizado !== 'true' &&
    (String(etapa).startsWith('aguardando_humano') || etapa === 'atendimento_humano') &&
    minutesSince(attrs.last_customer_message_at || attrs.humano_started_at) >= Number(config.regrasMinutos.filaSemAtendenteMinutos)
  ) {
    let teamId = 0;
    if (fluxo === 'meio_ambiente') teamId = Number(config.teams.transbordo_ma || 0);
    if (fluxo === 'sst') teamId = Number(config.teams.transbordo_sst || 0);

    actions.push({
      json: {
        conversationId: id,
        action: 'transbordo',
        shouldSend: true,
        message: msgTransbordo,
        shouldAssignTeam: teamId > 0,
        targetTeamId: teamId,
        shouldSaveAttributes: true,
        customAttributes: {
          ...attrs,
          transbordo_realizado: 'true',
          transbordo_em: new Date().toISOString(),
          transbordo_team_id: String(teamId),
          ultima_interacao_bot: new Date().toISOString()
        }
      }
    });
    continue;
  }

  // 3) Atendente humano sem resposta do cliente
  if (
    attrs.aguardando_cliente_humano === 'true' &&
    attrs.lembrete_cliente_enviado !== 'true' &&
    minutesSince(attrs.last_agent_message_at) >= Number(config.regrasMinutos.lembreteClienteMinutos)
  ) {
    actions.push({
      json: {
        conversationId: id,
        action: 'lembrete_cliente',
        shouldSend: true,
        message: msgLembrete,
        shouldSaveAttributes: true,
        customAttributes: {
          ...attrs,
          lembrete_cliente_enviado: 'true',
          lembrete_cliente_enviado_at: new Date().toISOString(),
          ultima_interacao_bot: new Date().toISOString()
        }
      }
    });
    continue;
  }

  // 4) Sem resposta após lembrete
  if (
    attrs.aguardando_cliente_humano === 'true' &&
    attrs.lembrete_cliente_enviado === 'true' &&
    minutesSince(attrs.lembrete_cliente_enviado_at) >= Number(config.regrasMinutos.encerrarAposLembreteMinutos)
  ) {
    actions.push({
      json: {
        conversationId: id,
        action: 'encerrar_inativo',
        shouldSend: true,
        message: msgEncerramento,
        shouldSetLabels: true,
        labelsToSet: Array.from(new Set([...labels, 'inativo'])),
        shouldSaveAttributes: true,
        shouldResolve: true,
        customAttributes: {
          ...attrs,
          fluxo: 'encerrado',
          etapa: 'encerrado',
          aguardando_cliente_humano: 'false',
          aguardando_agente: 'false',
          ultima_interacao_bot: new Date().toISOString()
        }
      }
    });
    continue;
  }
}

if (actions.length === 0) {
  return [{ json: { action: 'sem_acao', shouldSend: false, shouldSaveAttributes: false, shouldAssignTeam: false, shouldSetLabels: false, shouldResolve: false } }];
}

return actions;

